1","fixed","^1V",0,"^1U",0]]]],"^1I",null,"^1J",null,"^1K",null,"^1L","","^7","~m1769024870593","^1M","~m1769024870593","^1N","","^1O",null,"^1P","Spool_Dashboard","^1Q",null,"^1R",null]]],"projectPackageWeldedOutTransformer2",["^0",["^ ","n","pluginTemplate","v",["^ ","id","projectPackageWeldedOutTransformer2","^1>",null,"^1?",null,"^1@","function","^1A","Function","^1B",null,"^1C",null,"^1D",null,"^1E",["^1F",["funcBody","const rows = {{ weldedOutQuery.data }} || [];

// ----------------------
// STATUS HELPERS
// ----------------------
const isSpoolComplete = (status) => status === "05 - Spool Complete";
const isShipped       = (status) => status === "07 - Shipped";

const isWeldedOut = (status) =>
  isSpoolComplete(status) || isShipped(status);

// ----------------------
// Project-level counters
// ----------------------
const projectTotals = {};
const projectWeldedOut = {};

// ----------------------
// Package-level counters
// ----------------------
const packageTotals = {};
const packageWeldedOut = {};

// ----------------------
// OVERALL counters (NEW)
// ----------------------
let overallTotalSpools = 0;
let overallWeldedOutSpools = 0;

// ----------------------
// LOOP
// ----------------------
for (const r of rows) {
  const project = r.projects?.project_name || "Unknown Project";
  const pkg     = r.package_name || "Unknown Package";
  const status  = r.current_status;

  // ---- OVERALL ----
  overallTotalSpools += 1;

  if (isWeldedOut(status)) {
    overallWeldedOutSpools += 1;
  }

  // ---- PROJECT ----
  projectTotals[project] = (projectTotals[project] || 0) + 1;

  if (isWeldedOut(status)) {
    projectWeldedOut[project] =
      (projectWeldedOut[project] || 0) + 1;
  }

  // ---- PACKAGE ----
  packageTotals[pkg] = (packageTotals[pkg] || 0) + 1;

  if (isWeldedOut(status)) {
    packageWeldedOut[pkg] =
      (packageWeldedOut[pkg] || 0) + 1;
  }
}

// ----------------------
// BUILD RESULT
// ----------------------
const result = {
  // ⭐ NEW — Overall KPI
  overall_metrics: {
    total_spools: overallTotalSpools,
    welded_out_spools: overallWeldedOutSpools,
    percent_welded_out: overallTotalSpools
      ? Number(((overallWeldedOutSpools / overallTotalSpools) * 100).toFixed(2))
      : 0
  },

  project_metrics: Object.keys(projectTotals).map(project => {
    const total = projectTotals[project];
    const weldedOut = projectWeldedOut[project] || 0;

    return {
      project,
      total_spools: total,
      welded_out_spools: weldedOut,
      percent_welded_out: Number(((weldedOut / total) * 100).toFixed(2))
    };
  }),

  package_metrics: Object.keys(packageTotals).map(pkg => {
    const total = packageTotals[pkg];
    const weldedOut = packageWeldedOut[pkg] || 0;

    return {
      package: pkg,
      total_spools: total,
      welded_out_spools: weldedOut,
      percent_welded_out: Number(((weldedOut / total) * 100).toFixed(2))
    };
  })
};

// ----------------------
// SORTING
// ----------------------
result.project_metrics.sort(
  (a, b) => b.percent_welded_out - a.percent_welded_out
);

result.package_metrics.sort(
  (a, b) => b.percent_welded_out - a.percent_welded_out
