  }

  // Count done (complete + shipped) per project
  if ( status === "07 - Shipped") {
    projectComplete[project] = (projectComplete[project] || 0) + 1;
  }
}

// Build result object
const result = {
  project_metrics: Object.keys(projectTotals).map(project => ({
    project,
    total_spools: projectTotals[project],
    complete_spools: projectComplete[project] || 0,
    percent_complete: Number(((projectComplete[project] || 0) / projectTotals[project] * 100).toFixed(2))
