const data = {{ dateRangeQuery.data || [] }};
const metric = {{ metricSelect4.value || 'estimated_fab_hours' }};
const compareBy = {{ categorySelect4.value || 'assigned_shop' }};
const granularity = {{ periodGranularitySelect?.value || 'week' }}; // day | week | month

// --- Date range from picker ---
const rangeStart = {{ dateRangePicker_dateNeeded.value?.start }}
  ? moment({{ dateRangePicker_dateNeeded.value.start }})
  : moment('2000-01-01');

const rangeEnd = {{ dateRangePicker_dateNeeded.value?.end }}
  ? moment({{ dateRangePicker_dateNeeded.value.end }})
  : moment('2100-01-01');

// --- Count weekdays helper (Mon–Fri only) ---
function countWeekdays(start, end) {
  let count = 0;
  let cursor = start.clone();
  while (cursor.isSameOrBefore(end, 'day')) {
    const d = cursor.day();
    if (d !== 0 && d !== 6) count++;
    cursor.add(1, 'day');
  }
  return Math.max(count, 1);
}

// --- Count weekdays inside a bucket ---
function countWeekdaysInBucket(start, end, bucketStart, bucketEnd) {
  const s = moment.max(start, bucketStart);
  const e = moment.min(end, bucketEnd);
  if (e.isBefore(s)) return 0;
  return countWeekdays(s, e);
}

// --- Grouped results ---
const grouped = {};

data.forEach(pkg => {
  if (!pkg.projected_start_date || !pkg.date_needed) return;

  const start = moment(pkg.projected_start_date);
  const end   = moment(pkg.date_needed);
  if (!start.isValid() || !end.isValid() || end.isBefore(start)) return;

  // Clip to global range
  const actualStart = moment.max(start, rangeStart);
  const actualEnd   = moment.min(end, rangeEnd);
  if (actualEnd.isBefore(actualStart)) return;


  const totalHours = pkg[metric] || 0;
  const totalWorkdays = countWeekdays(start, end);
  const hoursPerWorkday = totalHours / totalWorkdays;

  const groupKey =
    compareBy === "projects.project_name"
      ? pkg.projects?.project_name || 'Unassigned'
      : pkg[compareBy] || 'Unassigned';

  // ---- Bucket Iteration ----
  let cursor = actualStart.clone().startOf(granularity);

  while (cursor.isSameOrBefore(actualEnd, granularity)) {
    const bucketStart = cursor.clone().startOf(granularity);
    const bucketEnd   = cursor.clone().endOf(granularity);


    // How many workdays from the project fall inside THIS bucket?
    const workdaysInBucket = countWeekdaysInBucket(start, end, bucketStart, bucketEnd);

    if (workdaysInBucket > 0) {
      const bucketHours = hoursPerWorkday * workdaysInBucket;
      const bucketKey = bucketEnd.format('YYYY-MM-DD');

      if (!grouped[groupKey]) grouped[groupKey] = {};
      if (!grouped[groupKey][bucketKey]) grouped[groupKey][bucketKey] = 0;

      grouped[groupKey][bucketKey] += bucketHours;
    }

    cursor.add(1, granularity);
  }
});

