const topKeys = Object.entries(totals)
  .sort((a,b) => b[1]-a[1])
  .slice(0,5)
  .map(([k]) => k);

results = results.filter(r => topKeys.includes(r.groupKey));

// ---- Chronological sort ----
return results.sort((a,b) => moment(a.bucket) - moment(b.bucket));




